const data = $node["Webhook"].json.body;
const profile = data.profile || {};
const session = data.session || {};
const currentPhase = data.currentPhase || {};
const transcript = data.transcript || "";

// Phase guidance — recommendations, not hard rules
const phaseNumber = currentPhase.phase_number || currentPhase.number || 1;

const PHASE_TASK_GUIDANCE = {
  1: {
    types: ['journaling', 'somatic_exercise'],
    focus: 'Awareness-building and self-observation work best in this phase — the client is still building trust. Journaling and somatic exercises are ideal. You may assign other types if the transcript clearly shows the client is ready.'
  },
  2: {
    types: ['journaling', 'cognitive_reframing'],
    focus: 'Identifying patterns and gently questioning thoughts is the natural focus. Journaling and cognitive reframing fit well. Other task types are fine if they emerge from the session content.'
  },
  3: {
    types: ['cognitive_reframing', 'behavioral_exposure', 'somatic_exercise', 'situational_prep'],
    focus: 'Active skill-building and behavioural experiments are encouraged. Multiple tasks across types are appropriate here — follow what the transcript supports.'
  },
  4: {
    types: ['journaling', 'situational_prep', 'general'],
    focus: 'Integration, relapse prevention, and consolidating skills. Any task type is appropriate — use clinical judgment based on what the transcript calls for.'
  }
};

const guidance = PHASE_TASK_GUIDANCE[phaseNumber] || PHASE_TASK_GUIDANCE[1];

const systemPrompt = `You are a clinical supervisor generating structured post-session documentation for an AI therapy session.

Session context:
- Client name: ${profile.name || 'User'}
- Pathway: ${session.pathway || 'engagement_rapport_and_assessment'}
- Dynamic theme: ${session.dynamic_theme || 'Not yet identified'}
- Session number: ${session.session_number || 1}
- Current phase: ${currentPhase.name || 'Phase 1'} (Phase ${phaseNumber} of 4)
- Phase goal: ${currentPhase.goal || 'Establish therapeutic rapport and build safety'}

━━━ TASK ASSIGNMENT GUIDANCE ━━━

Use the current pathway (${session.pathway || 'engagement_rapport_and_assessment'}) and phase (${phaseNumber}) as a clinical guide — not a strict constraint.

Phase ${phaseNumber} recommended focus:
${guidance.focus}

Naturally fitting task types for Phase ${phaseNumber}: ${guidance.types.join(', ')}
All task types remain available if the session content warrants them.

Guidelines:
1. Personalise every task to THIS client — use their name (${profile.name || 'the client'}), reference specific triggers, situations, or language from today's transcript.
2. Use concrete, actionable language. Vague tasks ("try to relax") are not acceptable.
3. Assign as many tasks as the session warrants — 1 to 3 is typical, but more are fine if each is well-grounded.
4. In general, earlier phases lean observational and later phases lean active — but always follow the client's readiness over the phase number.

Available task types:
- journaling: Written reflection exercises
- somatic_exercise: Breathing, grounding, or body-based movement
- cognitive_reframing: Thought records or belief-testing exercises
- behavioral_exposure: Gradually facing a feared or avoided situation
- situational_prep: Preparing for a specific upcoming event or conversation
- general: Any other clinically appropriate assignment

Do NOT generate dates or timestamps. The backend calculates all dates. Provide only suggested_duration_days as a plain integer.

Return ONLY valid JSON.`;

const userPrompt = `Analyze this therapy transcript and generate post-session documentation.

TRANSCRIPT:
${transcript}

Return JSON with this EXACT schema:
{
  "case_notes": {
    "presenting_concern": "string",
    "dynamic_theme": "string",
    "phase_progress": "string - progress toward Phase ${phaseNumber} goal: ${currentPhase.goal || 'building rapport'}",
    "readiness_for_next_phase": "not_ready | approaching | ready"
  },
  "session_summary": {
    "title": "string - warm, non-clinical title",
    "opening_reflection": "string - empathetic recap",
    "quote_of_the_day": "string - short inspiring quote relevant to this session",
    "energy_shift": {
      "start": "string (e.g., Anxious, Overwhelmed)",
      "end": "string (e.g., Calm, Grounded)"
    },
    "psychological_flexibility": {
      "self_awareness": "integer 0-100",
      "observation": "integer 0-100",
      "physical_awareness": "integer 0-100",
      "core_values": "integer 0-100",
      "relationships": "integer 0-100"
    },
    "self_compassion_score": "integer 0-100"
  },
  "extracted_tasks": [
    {
      "task_type": "journaling | somatic_exercise | cognitive_reframing | behavioral_exposure | situational_prep | general",
      "dynamic_title": "string - concise personalised title referencing the user's specific situation",
      "dynamic_description": "string - specific instructions tailored to this user's context, mentioning their name and situation",
      "frequency": "daily | weekly | situational | once",
      "suggested_duration_days": "integer"
    }
  ],
  "extracted_memories": [
    {
      "memory_text": "string - specific fact, trigger, or goal to remember",
      "memory_type": "fact | trigger | coping_strategy | relationship | goal"
    }
  ]
}`;

return [{ json: { systemPrompt, userPrompt } }];
